<script setup lang="ts">
import { ref, onMounted, onUnmounted } from 'vue';
import gsap from 'gsap';

// Reactive references for parallax effect
const containerRef = ref<HTMLElement | null>(null);
const parallaxX = ref(0);
const parallaxY = ref(0);

// Nodes configuration for the network
interface NetworkNode {
  id: number;
  cx: number;
  cy: number;
  r: number;
  color: string;
}

const nodes = ref<NetworkNode[]>([
  { id: 1, cx: 180, cy: 220, r: 6, color: '#DDAA33' }, // Ambar
  { id: 2, cx: 250, cy: 290, r: 5, color: '#2D8380' }, // Jade
  { id: 3, cx: 320, cy: 360, r: 7, color: '#E86A5B' }, // Coral
  { id: 4, cx: 844, cy: 220, r: 6, color: '#2D8380' },
  { id: 5, cx: 774, cy: 290, r: 5, color: '#DDAA33' },
  { id: 6, cx: 704, cy: 360, r: 7, color: '#2D8380' },
  { id: 7, cx: 250, cy: 734, r: 6, color: '#2D8380' },
  { id: 8, cx: 320, cy: 664, r: 5, color: '#E86A5B' },
  { id: 9, cx: 774, cy: 734, r: 6, color: '#DDAA33' },
  { id: 10, cx: 704, cy: 664, r: 5, color: '#2D8380' },
  { id: 11, cx: 512, cy: 120, r: 8, color: '#E86A5B' },
  { id: 12, cx: 920, cy: 512, r: 7, color: '#2D8380' },
  { id: 13, cx: 100, cy: 512, r: 7, color: '#2D8380' },
]);

// Parallax handler
const handleMouseMove = (e: MouseEvent) => {
  if (!containerRef.value) return;
  const rect = containerRef.value.getBoundingClientRect();
  const x = e.clientX - rect.left - rect.width / 2;
  const y = e.clientY - rect.top - rect.height / 2;
  
  // Normalize values between -1 and 1
  parallaxX.value = x / (rect.width / 2);
  parallaxY.value = y / (rect.height / 2);
};

const handleMouseLeave = () => {
  // Smoothly return to center
  gsap.to(parallaxX, { value: 0, duration: 0.8 });
  gsap.to(parallaxY, { value: 0, duration: 0.8 });
};

// Lifecycle animations
let intervals: number[] = [];
let gsapTweens: gsap.core.Tween[] = [];

onMounted(() => {
  // 1. Initial draw-in animation for the iguana paths
  const paths = document.querySelectorAll('.iguana-path');
  paths.forEach((pathElement) => {
    const path = pathElement as SVGPathElement;
    const length = path.getTotalLength();
    path.style.strokeDasharray = `${length}`;
    path.style.strokeDashoffset = `${length}`;
    
    // Animate stroke drawing first
    const drawTween = gsap.to(path, {
      strokeDashoffset: 0,
      duration: 2.2,
      ease: 'power1.out',
      delay: Math.random() * 0.6,
      onComplete: () => {
        // Then fade in fill
        const fillTween = gsap.to(path, { fillOpacity: 0.95, duration: 1.5 });
        gsapTweens.push(fillTween);
      }
    });
    gsapTweens.push(drawTween);
  });

  // 2. Breathing scale animation of the main iguana
  const breathingTween = gsap.to('.iguana-group', {
    scale: 1.015,
    duration: 4.5,
    repeat: -1,
    yoyo: true,
    ease: 'sine.inOut'
  });
  gsapTweens.push(breathingTween);

  // 3. Central Core rings pulse
  const rings = document.querySelectorAll('.core-ring');
  rings.forEach((ringElement, index) => {
    const ring = ringElement as SVGCircleElement;
    gsap.set(ring, { attr: { r: 12 }, opacity: 0.9 });
    const ringTween = gsap.to(ring, {
      attr: { r: 100 },
      opacity: 0,
      duration: 3.5,
      delay: index * 1.1,
      repeat: -1,
      ease: 'power1.out'
    });
    gsapTweens.push(ringTween);
  });

  // 4. Random glowing of nodes in the network
  const nodeGlowInterval = window.setInterval(() => {
    const nodeElements = document.querySelectorAll('.network-node');
    if (nodeElements.length > 0) {
      const randomIndex = Math.floor(Math.random() * nodeElements.length);
      const selectedNode = nodeElements[randomIndex] as SVGCircleElement;
      
      const originalRadius = parseFloat(selectedNode.getAttribute('r') || '5');
      
      gsap.to(selectedNode, {
        attr: { r: originalRadius * 1.8 },
        opacity: 1,
        duration: 0.9,
        yoyo: true,
        repeat: 1,
        ease: 'sine.inOut',
        onComplete: () => {
          gsap.set(selectedNode, { attr: { r: originalRadius }, opacity: 0.75 });
        }
      });
    }
  }, 1200);
  intervals.push(nodeGlowInterval);

  // 5. Digital circuit energy pulse dashes
  const pulses = document.querySelectorAll('.pulse-path');
  pulses.forEach((pulseElement) => {
    const pulse = pulseElement as SVGPathElement;
    const length = pulse.getTotalLength();
    pulse.style.strokeDasharray = `30 ${length - 30}`;
    
    const pulseTween = gsap.fromTo(pulse, 
      { strokeDashoffset: length },
      {
        strokeDashoffset: 0,
        duration: 3 + Math.random() * 3,
        repeat: -1,
        ease: 'none'
      }
    );
    gsapTweens.push(pulseTween);
  });
});

onUnmounted(() => {
  intervals.forEach(clearInterval);
  gsapTweens.forEach(tween => tween.kill());
});
</script>

<template>
  <div 
    ref="containerRef"
    class="relative w-full aspect-square max-w-[650px] mx-auto flex items-center justify-center overflow-visible select-none"
    @mousemove="handleMouseMove"
    @mouseleave="handleMouseLeave"
  >
    <!-- Background Ambient Glow Layer -->
    <div 
      class="absolute inset-0 rounded-full blur-[140px] opacity-35 -z-20 pointer-events-none transition-transform duration-500 ease-out"
      :style="{ transform: `translate3d(${parallaxX * -15}px, ${parallaxY * -15}px, 0)` }"
    >
      <div class="absolute w-2/3 h-2/3 top-1/4 left-1/4 rounded-full bg-gradient-to-tr from-jade to-petroleo"></div>
      <div class="absolute w-1/2 h-1/2 top-10 left-10 rounded-full bg-amber/30"></div>
    </div>

    <!-- MAIN SVG -->
    <svg 
      viewBox="0 0 1024 1024" 
      fill="none" 
      xmlns="http://www.w3.org/2000/svg"
      class="w-full h-full relative z-10 overflow-visible"
    >
      <defs>
        <!-- Iguana Premium Gradient -->
        <linearGradient id="iguanaGrad" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stop-color="#234A57" /> <!-- Petroleo -->
          <stop offset="50%" stop-color="#2D8380" /> <!-- Jade -->
          <stop offset="100%" stop-color="#6F6C2B" /> <!-- Olivo -->
        </linearGradient>

        <linearGradient id="circuitsGrad" x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stop-color="#2D8380" stop-opacity="0.4" />
          <stop offset="100%" stop-color="#234A57" stop-opacity="0.1" />
        </linearGradient>

        <!-- Glow filter for elements -->
        <filter id="glow" x="-20%" y="-20%" width="140%" height="140%">
          <feGaussianBlur stdDeviation="6" result="blur" />
          <feMerge>
            <feMergeNode in="blur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
        
        <filter id="strongGlow" x="-50%" y="-50%" width="200%" height="200%">
          <feGaussianBlur stdDeviation="12" result="blur" />
          <feMerge>
            <feMergeNode in="blur" />
            <feMergeNode in="SourceGraphic" />
          </feMerge>
        </filter>
      </defs>

      <!-- LAYER 1: Topographical relief curves (Slight movement, deepest background) -->
      <g 
        class="topography-layer"
        :style="{ transform: `translate3d(${parallaxX * -8}px, ${parallaxY * -8}px, 0)`, transition: 'transform 0.2s ease-out' }"
      >
        <!-- Topographical lines of Oaxaca relief -->
        <path d="M-50,750 C180,680 350,880 650,780 C880,700 950,850 1100,800" fill="none" stroke="#234A57" stroke-width="1.5" stroke-opacity="0.08" />
        <path d="M-50,600 C280,480 450,720 750,550 C980,420 1050,650 1100,600" fill="none" stroke="#234A57" stroke-width="1" stroke-opacity="0.05" />
        <path d="M-50,450 C80,380 280,500 580,380 C780,290 880,430 1100,380" fill="none" stroke="#234A57" stroke-width="1" stroke-opacity="0.04" />
        <path d="M-50,300 C150,220 300,340 500,240 C680,150 780,290 1100,220" fill="none" stroke="#234A57" stroke-width="0.8" stroke-opacity="0.02" />
      </g>

      <!-- LAYER 2: Mitla digital circuits & nodes (Medium depth) -->
      <g 
        class="circuits-layer"
        :style="{ transform: `translate3d(${parallaxX * -4}px, ${parallaxY * -4}px, 0)`, transition: 'transform 0.2s ease-out' }"
      >
        <!-- Mitla Grecas Circuit Traces -->
        <!-- Top Left Greca -->
        <path d="M120,150 L200,150 L200,220 L270,220 L270,290 L340,290 L340,360 L410,360" fill="none" stroke="url(#circuitsGrad)" stroke-width="1.5" />
        <path d="M120,150 L200,150 L200,220 L270,220 L270,290 L340,290 L340,360 L410,360" class="pulse-path" fill="none" stroke="#2D8380" stroke-width="2" filter="url(#glow)" />
        
        <!-- Top Right Greca -->
        <path d="M904,150 L824,150 L824,220 L754,220 L754,290 L684,290 L684,360 L614,360" fill="none" stroke="url(#circuitsGrad)" stroke-width="1.5" />
        <path d="M904,150 L824,150 L824,220 L754,220 L754,290 L684,290 L684,360 L614,360" class="pulse-path" fill="none" stroke="#2D8380" stroke-width="2" filter="url(#glow)" />

        <!-- Bottom Left Greca -->
        <path d="M120,874 L200,874 L200,804 L270,804 L270,734 L340,734 L340,664 L410,664" fill="none" stroke="url(#circuitsGrad)" stroke-width="1.5" />
        <path d="M120,874 L200,874 L200,804 L270,804 L270,734 L340,734 L340,664 L410,664" class="pulse-path" fill="none" stroke="#2D8380" stroke-width="2" filter="url(#glow)" />

        <!-- Bottom Right Greca -->
        <path d="M904,874 L824,874 L824,804 L754,804 L754,734 L684,734 L684,664 L614,664" fill="none" stroke="url(#circuitsGrad)" stroke-width="1.5" />
        <path d="M904,874 L824,874 L824,804 L754,804 L754,734 L684,734 L684,664 L614,664" class="pulse-path" fill="none" stroke="#2D8380" stroke-width="2" filter="url(#glow)" />

        <!-- Additional Network connections forming a web -->
        <line x1="180" y1="220" x2="250" y2="290" stroke="#2D8380" stroke-width="1" stroke-opacity="0.25" />
        <line x1="250" y1="290" x2="320" y2="360" stroke="#2D8380" stroke-width="1" stroke-opacity="0.25" />
        <line x1="320" y1="360" x2="100" y2="512" stroke="#234A57" stroke-width="1" stroke-opacity="0.2" />
        <line x1="844" y1="220" x2="774" y2="290" stroke="#2D8380" stroke-width="1" stroke-opacity="0.25" />
        <line x1="774" y1="290" x2="704" y2="360" stroke="#2D8380" stroke-width="1" stroke-opacity="0.25" />
        <line x1="704" y1="360" x2="920" y2="512" stroke="#234A57" stroke-width="1" stroke-opacity="0.2" />
        <line x1="250" y1="734" x2="320" y2="664" stroke="#2D8380" stroke-width="1" stroke-opacity="0.25" />
        <line x1="774" y1="734" x2="704" y2="664" stroke="#2D8380" stroke-width="1" stroke-opacity="0.25" />
        
        <!-- Connections into the central area where the Iguana lives -->
        <path d="M100,512 L300,512 L380,480" fill="none" stroke="url(#circuitsGrad)" stroke-width="1.2" />
        <path d="M920,512 L720,512 L640,480" fill="none" stroke="url(#circuitsGrad)" stroke-width="1.2" />
        <path d="M512,120 L512,240" fill="none" stroke="url(#circuitsGrad)" stroke-width="1.2" />
        
        <!-- Network Nodes (Circles with glowing backgrounds) -->
        <g v-for="node in nodes" :key="node.id" class="node-group">
          <!-- Node Outer soft glow -->
          <circle 
            :cx.attr="node.cx" 
            :cy.attr="node.cy" 
            :r.attr="node.r * 2.5" 
            :fill="node.color" 
            opacity="0.15" 
            filter="url(#glow)"
          />
          <!-- Node Core -->
          <circle 
            :cx.attr="node.cx" 
            :cy.attr="node.cy" 
            :r.attr="node.r" 
            :fill="node.color" 
            class="network-node transition-all duration-300"
            opacity="0.75"
          />
        </g>
      </g>

      <!-- LAYER 3: The Iguana and the Core (Forward layer, main focus) -->
      <g 
        class="iguana-layer"
        :style="{ transform: `translate3d(${parallaxX * 6}px, ${parallaxY * 6}px, 0)`, transition: 'transform 0.2s ease-out' }"
      >
        <!-- Iguana Logo Wrapper -->
        <g class="iguana-group origin-[525px_512px]">
          <!-- Shadow/Glow behind the Iguana -->
          <g opacity="0.3" filter="url(#strongGlow)">
            <path d="M397.6 243.364C395.25 244.804 394.3 248.253 395.6 250.741C395.95 251.396 398.15 253.054 400.5 254.451C414.8 263.007 431.6 276.976 442.65 289.373C448.8 296.314 459.5 309.802 459.5 310.632C459.5 310.85 456.8 311.941 453.5 313.076L447.55 315.128L440.9 309.191C406.3 278.154 366.75 260.912 321 256.896C310.5 255.979 294.2 255.543 291.75 256.154C287.55 257.114 285.55 260.65 287.25 263.793C288.45 265.975 289.3 266.368 296 267.94C327.3 275.142 355.45 291.163 382.85 317.398C389.6 323.858 403 338.176 402.95 338.918C402.95 339.355 393.95 345.554 392.85 345.947C392.5 346.034 390 344.331 387.25 342.149C379.5 335.95 368.3 328.267 360.4 323.727C328.85 305.612 298.7 298.147 257.2 298.104H248.65L247.25 296.27C244.1 292.123 240.2 290.246 234.7 290.246C228.1 290.246 223.15 292.734 220.05 297.667C218.4 300.286 218.25 300.766 218.25 304.215C218.25 307.358 218.45 308.231 219.6 310.108C221.1 312.683 224.45 315.521 227.6 316.918C230.6 318.271 236 318.533 239.5 317.529C242.1 316.787 246 313.906 248.05 311.199C248.85 310.152 248.95 310.152 251.9 310.675C262.05 312.509 282.4 320.41 293.25 326.739C313.25 338.395 330.75 352.887 351.5 375.063L354.7 378.467L350.45 382.178C348.15 384.186 346.1 385.845 345.9 385.845C345.65 385.845 342.7 383.924 339.3 381.523C318.65 367.162 300.1 358.562 278 353.149C262.55 349.395 249.7 347.955 229.1 347.649L217.95 347.474L216.4 345.466C213.4 341.538 209.15 339.617 203.5 339.573C197 339.573 192.3 342.28 189.35 347.736C188 350.268 187.9 350.879 188.1 353.76C188.55 359.479 191.85 363.669 197.85 366.07C200.25 367.031 201.1 367.162 204.45 366.987C210 366.725 213.9 364.717 217.05 360.526L217.9 359.435L222.3 360.439C233.2 362.927 245.9 368.078 257.65 374.713C266.85 379.864 271.2 382.745 280.45 389.773C290.75 397.587 310.05 415.179 309.95 416.62C309.95 416.838 307.4 418.977 304.25 421.29L298.6 425.568L294.65 422.6C283.4 414.088 270.85 407.016 258.6 402.258C246.25 397.413 235.25 394.968 219.15 393.484C212.7 392.873 212.2 392.916 210.2 393.659C206.65 395.